// Hand-authored shared helpers for the transcendence (novel) commands.
// No "Generated by CLI Printing Press" header so regen-merge classifies
// this file as novel and never overwrites it.
//
// The novel commands read from the single local `resources` table keyed by
// `resource_type` (the store does NOT keep per-type tables for agents,
// checks, alerts, etc.). These helpers centralise opening that store,
// scoring agents (via internal/fleet), and the loose window parser the
// prior 4.19 implementation exposed, so behaviour stays back-compatible.

package cli

import (
	"context"
	"database/sql"
	"strings"
	"time"

	"github.com/spf13/cobra"
	"tactical-rmm-pp-cli/internal/cliutil"
	"tactical-rmm-pp-cli/internal/store"
)

// tRO returns the read-only MCP annotation shared by every non-mutating
// novel command. Mutating commands (bulk-run, maintenance set) omit it.
func tRO() map[string]string { return map[string]string{"mcp:read-only": "true"} }

// tOpen opens (or creates) the default local store. Callers must Close.
func tOpen(ctx context.Context) (*store.Store, error) {
	return store.OpenWithContext(ctx, defaultDBPath("tactical-rmm-cli"))
}

// tQInt runs a single-row, single-column integer query and returns 0 on any
// error or NULL. Used for the fleet-health counters.
func tQInt(ctx context.Context, db *sql.DB, query string, args ...interface{}) int {
	var n sql.NullInt64
	_ = db.QueryRowContext(ctx, query, args...).Scan(&n)
	return int(n.Int64)
}

// tWindow parses a loose duration window (e.g. 2h, 24h, 7d, 1w). It preserves
// the prior 4.19 behaviour: empty or unparseable input defaults to 24h. It
// delegates to cliutil.ParseDurationLoose for the real parse (which adds the
// d/w suffixes time.ParseDuration lacks) and only adds the never-error default.
// A negative window is clamped to its absolute value, since a negative duration
// would compute a cutoff in the future and silently match nothing.
func tWindow(s string) time.Duration {
	s = strings.TrimSpace(s)
	if s == "" {
		return 24 * time.Hour
	}
	d, err := cliutil.ParseDurationLoose(s)
	if err != nil {
		return 24 * time.Hour
	}
	if d < 0 {
		d = -d
	}
	return d
}

// baseAgentCols is the shared SQL projection for the five base agent columns
// (agent_id, hostname, client_name, site_name, status) read out of the shared
// resources table. Used by triage, coverage and agents stale so the column
// order stays identical and the scan helper below can rely on it.
const baseAgentCols = "json_extract(data,'$.agent_id'),json_extract(data,'$.hostname'),json_extract(data,'$.client_name'),json_extract(data,'$.site_name'),json_extract(data,'$.status')"

// scanBaseAgent scans the five baseAgentCols columns from the current row into a
// tAgentRow. Any extra dest pointers are scanned after the five base columns, so
// a caller whose SELECT appends columns (e.g. agents stale adds last_seen) can
// still use this helper by passing those destinations. Returns (row, false) on
// scan error so callers can skip cleanly. Commands that need post-scan derived
// fields from many extra columns (e.g. triage's scoring) keep their own scan
// using baseAgentCols as the leading projection.
func scanBaseAgent(rows *sql.Rows, extra ...any) (tAgentRow, bool) {
	var aid, host, cl, st, status sql.NullString
	dest := append([]any{&aid, &host, &cl, &st, &status}, extra...)
	if rows.Scan(dest...) != nil {
		return tAgentRow{}, false
	}
	return tAgentRow{AgentID: aid.String, Hostname: host.String, Client: cl.String, Site: st.String, Status: status.String}, true
}

// sqlISOToDatetime returns a SQLite expression that coerces an ISO-8601
// timestamp stored at data.$<jsonPath> into a comparable `datetime()` value by
// stripping the 'T' separator and trailing 'Z'. Centralised so since,
// agents-stale and alerts-digest share one definition.
func sqlISOToDatetime(jsonPath string) string {
	return "datetime(REPLACE(REPLACE(json_extract(data,'$." + jsonPath + "'),'T',' '),'Z',''))"
}

// novelLocalRead opens the store, runs the unsynced/stale sync hints for the
// given resource (writes only to stderr), and hands back the open store. The
// caller owns Close. Returns (nil, nil) when the store cannot be opened so
// the command can still emit an honest empty result.
func novelLocalRead(cmd *cobra.Command, flags *rootFlags, resource string) *store.Store {
	s, err := tOpen(cmd.Context())
	if err != nil || s == nil {
		return nil
	}
	if !hintIfUnsynced(cmd, s, resource) {
		hintIfStale(cmd, s, resource, flags.maxAge)
	}
	return s
}
